class Solution {
    public boolean equalFrequency(String word) {
        for (int i = 0; i < word.length(); i++) {
            char c = word.charAt(i);
            int[] count = new int[26];
            for (int j = 0; j < word.length(); j++) {
                if (j != i) {
                    count[word.charAt(j) - 'a']++;
                }
            }
            boolean flag = true;
            int max = 0;
            for (int k = 0; k < 26; k++) {
                if (count[k] != 0) {
                    if (count[k] % word.length() != 0) {
                        flag = false;
                        break;
                    }
                    max = Math.max(max, count[k]);
                }
            }
            if (flag && max == word.length()) {
                return true;
            }
        }
        return false;
    }
}
